function start(db){ const s = srvMod.createServer({ db }); return new Promise(r=>s.listen(0,()=>r(s))); }
async function J(method, path, body){ const port = SRV.address().port; const res = await fetch(`http://localhost:${port}${path}`, { method, headers: body?{ "content-type":"application/json"}:{}, body: body?JSON.stringify(body):undefined }); let j=null; try{ j=await res.json(); }catch{} return { code: res.status, j }; }
