console.log("GET /1:", (await J("GET","/notes/1")).code);
console.log("GET /999:", (await J("GET","/notes/999")).code);
console.log("PUT /1:", (await J("PUT","/notes/1",{title:"updated"})).code);
console.log("PUT /1 invalid:", (await J("PUT","/notes/1",{title:""})).code);
console.log("PUT /999:", (await J("PUT","/notes/999",{title:"x"})).code);
console.log("DELETE /2:", (await J("DELETE","/notes/2")).code);
console.log("DELETE /2 again:", (await J("DELETE","/notes/2")).code);
