// restart -> reopen same file
let db2 = dbMod.openDb ? dbMod.openDb(DBP) : dbMod.default(DBP);
SRV = await start(db2);
const after = await J("GET","/notes/1");
console.log("AFTER RESTART GET /1:", after.code, "title:", after.j?.title);
SRV.close();
'
